var add_new_player = 0;
var invalid_player_name = '';

function validate_player(player_name)
{
	invalid_player_name = '';
	if('Add New Player' == player_name)
	{
		var checkbox_0 = document.getElementById('checkbox_0');
		if(checkbox_0)
		{
			if(checkbox_0.checked)
			{
				add_new_player = 1;
				return false;
			}
		}
	}
	
	if(Object.values(children_not_valid).includes(player_name))
	{
		invalid_player_name = player_name;
		return false;
	}
	
	return true;
}
</script>
