function parseTicketVariations($text) {
    $cleanedText = preg_replace('/<\/?p>/', '', $text);
	
    $lines = explode('<br />', $cleanedText);
    
    $ticketVariations = [];
    
    $regex = '/(.+): \$(\d+)/';
    
    foreach ($lines as $line) {
        if (preg_match($regex, $line, $matches)) {
            $ticketName = trim($matches[1]);
            $ticketPrice = intval($matches[2]);
            
            $ticketObject = [
                'etn_ticket_name' => $ticketName,
                'etn_ticket_price' => $ticketPrice,
            ];
            
            $ticketVariations[] = $ticketObject;
        }
    }
    
    return $ticketVariations;
}
