		var player_selects = document.querySelectorAll('.player_select');
		if(player_selects)
		{
			if(current_select.value == 'Add New Player')
			{
				var first_name_label = document.getElementById("first_name_label_" + current_select.dataset.player_id);
				first_name_label.style.display = 'block';
				var first_name = document.getElementById("first_name_" + current_select.dataset.player_id);
				first_name.style.display = 'block';
				var last_name_label = document.getElementById("last_name_label_" + current_select.dataset.player_id);
				last_name_label.style.display = 'block';
				var last_name = document.getElementById("last_name_" + current_select.dataset.player_id);
				last_name.style.display = 'block';
				var checkbox_label = document.getElementById("checkbox_label_" + current_select.dataset.player_id);
				checkbox_label.style.display = 'block';
			}
			else
			{
				var first_name_label = document.getElementById("first_name_label_" + current_select.dataset.player_id);
				first_name_label.style.display = 'none';
				var first_name = document.getElementById("first_name_" + current_select.dataset.player_id);
				first_name.style.display = 'none';
				var last_name_label = document.getElementById("last_name_label_" + current_select.dataset.player_id);
				last_name_label.style.display = 'none';
				var last_name = document.getElementById("last_name_" + current_select.dataset.player_id);
				last_name.style.display = 'none';
				var checkbox_label = document.getElementById("checkbox_label_" + current_select.dataset.player_id);
				checkbox_label.style.display = 'none';
			}
			
			for(var i = 0; i < player_selects.length; i++)
			{
				taken_options[taken_options.length] = player_selects[i].value;
			}
			
			for(var i = 0; i < player_selects.length; i++)
			{
				if(player_selects[i].id == current_select.id)
					continue;
				
				var options = player_selects[i].querySelectorAll('option');
				for(var j = 0; j < options.length; j++)
				{
					if(options[j].value == current_select.value && current_select.value != '')
						options[j].style.display = 'none';
					else if(!inArray(options[j].value, taken_options))
						options[j].style.display = 'block';
				}
			}
		}
	}
	
