        var submitButton = document.querySelector('button[name="submit"]');
		
		var invite_others = document.getElementById("invite_others");
		if(group_select.value == 1)//1-on-1 purchase
		{
			if(invite_others)
				invite_others.style.display = 'none';
			
			click_qty('qt-add');
			ticket_input_0.value = 1;
			//variation_picked_total_qty.value = 1;
			//book_button.style.display = 'none';
			book_button.style.display = 'block';
			submitButton.style.display = 'block';
			group_players.style.display = 'none';
			
			document.getElementById("players_count").value = 1;
		}
		else//Public Group or Private Group
		{
			if(invite_others)
				invite_others.style.display = 'block';
			
			if(group_select_value_last <= 1)
			{
				click_qty('qt-sub');
				ticket_input_0.value = 0;
				document.getElementById("players_count").value = 0;
			}
			//variation_picked_total_qty.value = 0;
			book_button.style.display = 'block';
			submitButton.style.display = 'none';
			group_players.style.display = 'block';
		}
		
		setTimeout(quantity_changed, 100);
		
		//alert(ticket_input_0.value);
	}

