?>			
	        var waiverButton = document.createElement("button");
	        waiverButton.name = "view_waiver";
	        waiverButton.id = "view_waiver";
	        waiverButton.className = "etn-btn etn-primary view_waiver";
	        waiverButton.type = "button";
	        waiverButton.textContent = "View & Sign Waiver";
	        waiverButton.onclick = show_waiver;
	
			form.insertBefore(waiverButton, submitButton);
<?php
		}
?>			
			
	        var book_button = document.createElement("button");
	        book_button.name = "book_button";
	        book_button.id = "book_button";
	        book_button.className = "etn-btn etn-primary book_button";
	        book_button.type = "button";
			
	        book_button.textContent = "Book Now";
	        book_button.onclick = book_button_click;
	
			form.insertBefore(book_button, submitButton);
			
			var observer = new MutationObserver(function(mutations) {
			    mutations.forEach(function(mutation) {
			        if (mutation.attributeName === 'disabled') {
						//console.log('mutation');
						
						if(mutation.target.type == 'submit')
						{
							set_book_button_disabled();
						}
			        }
			    });
			});
			
			var config = { attributes: true, attributeFilter: ['disabled'] };
			
			observer.observe(submitButton, config);

			submitButton.addEventListener('click', function(event) {
				if(!waiver_read())
				{
					event.preventDefault();
					show_waiver();
				}
			});
			
			var have_read = document.getElementById("have_read");
			have_read.addEventListener('click', function(event) {
				set_book_button_disabled();
			});
			
			var confirm_waiver = document.getElementById("confirm_waiver");
			confirm_waiver.addEventListener('click', function(event) {
				set_book_button_disabled();
			});
			
			submitButton.style.display = 'none';
	    }
	});
	
	function set_book_button_disabled()
	{
		//console.log('set_book_button_disabled()');
		var book_button = document.getElementById("book_button");
		var form = document.querySelector("#purchase_ticket_form");
		var submitButton = form.querySelector('button[name="submit"]');
		var submit_disabled_state = submitButton.disabled;
		if(submit_disabled_state)
		{
			book_button.disabled = true;
			//book_button.innerHTML = 'disabled';
			return;
		}
		
		var is_waiver_read = waiver_read();
		
		if(!is_waiver_read)
		{
			book_button.disabled = true;
			//book_button.innerHTML = 'disabled';
			return;
		}
		
		book_button.disabled = false;
		//book_button.innerHTML = 'not disabled';
	}
<?php
	}
?>
    </script>
