<?php
if($location_name || $room_area)
{
?>
<script>
(function () {
  var run = function () {
    var locationName = <?php echo wp_json_encode( $location_name ); ?>;
    var roomArea     = <?php echo wp_json_encode( $room_area ); ?>;

    var li = document.querySelector('.etn-event-date-meta li:nth-child(2)');
    if (!li) return;

    var parts = [locationName, roomArea].filter(Boolean);
    if (!parts.length) return;

    var icon = li.querySelector('i');
    var text = document.createTextNode(' ' + parts.join(', ') + ' ');

    if (icon && icon.nextSibling) {
      li.insertBefore(text, icon.nextSibling);
    } else {
      li.insertBefore(text, li.firstChild);
    }
  };

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', run);
  } else {
    run();
  }
})();
</script>
<?php
}
?>